#pragma once
// =====================================================================
// embed_secret.h — 32-byte secret used as HKDF IKM for embedded DLL
// resources (Andromeda + ProxyHook). Regenerated by CMake on each
// configure when no override is present (see CMakeLists.txt
// "regen_embed_secret" custom target). The Python encryption helper
// reads the same secret from this header at build time so format stays
// in sync.
//
// This default value exists only so out-of-the-box build works. The CI/
// packaging pipeline writes a per-release secret here before encrypting
// the resources, then strips this file from any source archive shipped
// to testers.
// =====================================================================

#include <cstdint>

namespace embed_secret {

inline constexpr uint8_t kEmbedSecret[32] = {
	0x44, 0x6F, 0x74, 0x61, 0x46, 0x61, 0x72, 0x6D,
	0x2D, 0x44, 0x65, 0x76, 0x2D, 0x45, 0x6D, 0x62,
	0x65, 0x64, 0x53, 0x65, 0x63, 0x72, 0x65, 0x74,
	0x2D, 0x76, 0x31, 0x2D, 0x30, 0x30, 0x30, 0x31,
};

} // namespace embed_secret
